const resposta = $input.first().json.message.content;

let resultado;
try {
  resultado = JSON.parse(resposta);
} catch (e) {
  const jsonMatch = resposta.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    resultado = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('OpenAI nao retornou JSON valido: ' + resposta);
  }
}

const sentimentosValidos = ['positivo', 'negativo', 'neutro'];
if (!sentimentosValidos.includes(resultado.sentimento)) {
  throw new Error('Sentimento invalido: ' + resultado.sentimento);
}

return {
  sentimento: resultado.sentimento,
  confianca: parseFloat(resultado.confianca.toFixed(2)),
  palavras_chave: resultado.palavras_chave
};
